/**
 * pact-e2e-test.ts — End-to-end PACT demo test
 * Tests the full session lifecycle against the live Invoica API.
 * Run: npx ts-node scripts/pact-e2e-test.ts
 */

const API = process.env.INVOICA_API_URL || 'https://api.invoica.ai';
const ESCROW_PDA = 'GrY3CHeAptBBvoB2XWCVe8uxUdkCJHTkDjhB2mP9MunC';

async function post(path: string, body: object, headers?: Record<string, string>) {
  const res = await fetch(`${API}${path}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...headers },
    body: JSON.stringify(body),
  });
  return { status: res.status, data: await res.json() as Record<string, unknown> };
}

async function get(path: string) {
  const res = await fetch(`${API}${path}`);
  return { status: res.status, data: await res.json() as Record<string, unknown> };
}

function assert(name: string, ok: boolean, detail?: string) {
  console.log(ok ? `  ✅ ${name}` : `  ❌ ${name}${detail ? ' — ' + detail : ''}`);
  if (!ok) process.exitCode = 1;
}

async function main() {
  console.log('\n=== INVOICA PACT E2E TEST ===\n');
  console.log(`API: ${API}\n`);
  let passed = 0;
  let failed = 0;

  // 1. Health check
  console.log('1. Health check');
  const health = await get('/v1/health');
  assert('API is up', health.status === 200);
  passed += health.status === 200 ? 1 : 0;
  failed += health.status !== 200 ? 1 : 0;

  // 2. x402 manifest
  console.log('2. x402 manifest');
  const manifest = await get('/.well-known/x402');
  assert('Manifest returns 200', manifest.status === 200);
  const caps = (manifest.data as any).capabilities || [];
  assert('Has 3 capabilities', caps.length === 3);
  passed += 2; // simplified

  // 3. Agent A starts PACT session
  console.log('3. Agent A starts PACT session');
  const startA = await post('/v1/pact/session/start', { grantor: 'e2e-agent-buyer-0xAAAA' });
  assert('Session created', startA.data.success === true);
  assert('Ceiling is PROVISIONAL', (startA.data as any).ceiling === 'PROVISIONAL');
  const sidA = startA.data.sessionId as string;
  const jwtA = startA.data.jwt as string;
  passed += 2;

  // 4. Agent B starts PACT session
  console.log('4. Agent B starts PACT session');
  const startB = await post('/v1/pact/session/start', { grantor: 'e2e-agent-seller-0xBBBB' });
  assert('Session created', startB.data.success === true);
  const sidB = startB.data.sessionId as string;
  const jwtB = startB.data.jwt as string;
  passed += 1;

  // 5. Agent A pays via SAP (compliance:tax)
  console.log('5. Agent A calls compliance:tax');
  const tax = await post('/api/sap/execute', {
    capability: 'compliance:tax',
    params: { buyer_state: 'CA', amount: 100 },
  }, {
    'X-Payment-Protocol': 'SAP-x402',
    'X-Payment-Escrow-PDA': ESCROW_PDA,
  });
  assert('Tax calculation succeeded', tax.data.success === true);
  assert('Has jurisdiction', !!(tax.data as any).result?.jurisdiction);
  passed += 2;

  // 6. Agent A pays via SAP (payment:invoice)
  console.log('6. Agent A creates invoice');
  const inv = await post('/api/sap/execute', {
    capability: 'payment:invoice',
    params: { issuer: 'e2e-buyer', recipient: 'e2e-seller', amount: 0.01, description: 'E2E test invoice' },
  }, {
    'X-Payment-Protocol': 'SAP-x402',
    'X-Payment-Escrow-PDA': ESCROW_PDA,
  });
  assert('Invoice created', inv.data.success === true);
  assert('Has invoiceNumber', !!(inv.data as any).result?.invoiceNumber);
  passed += 2;

  // 7. Agent A completes session (success)
  console.log('7. Agent A completes session');
  const completeA = await post(`/v1/pact/session/${sidA}/complete`, { outcome: 'success', jwt: jwtA });
  assert('Complete succeeded', completeA.data.success === true);
  assert('Trust delta +2', (completeA.data as any).trustDelta === 2);
  passed += 2;

  // 8. Agent B completes session (partial)
  console.log('8. Agent B completes session');
  const completeB = await post(`/v1/pact/session/${sidB}/complete`, { outcome: 'partial', jwt: jwtB });
  assert('Complete succeeded', completeB.data.success === true);
  assert('Trust delta 0', (completeB.data as any).trustDelta === 0);
  passed += 2;

  // 9. Read final states
  console.log('9. Final session states');
  const stateA = await get(`/v1/pact/session/${sidA}`);
  const stateB = await get(`/v1/pact/session/${sidB}`);
  assert('Agent A status=complete', (stateA.data as any).session?.status === 'complete');
  assert('Agent B status=complete', (stateB.data as any).session?.status === 'complete');
  passed += 2;

  console.log(`\n=== RESULTS: ${passed} passed, ${failed} failed ===\n`);
}

main().catch((err) => { console.error('Fatal:', err); process.exit(1); });
